  return attachTagsToBookmarks(bookmarks, userId);
}

function tagIdsBelongToUser(tagIds: number[], userId: number): boolean {
  if (tagIds.length === 0) {
    return true;
  }

  const placeholders = tagIds.map(() => "?").join(", ");
  const { count } = db
    .prepare(`SELECT COUNT(*) AS count FROM tags WHERE user_id = ? AND id IN (${placeholders})`)
    .get(userId, ...tagIds) as { count: number };

  return count === tagIds.length;
}

function replaceBookmarkTags(bookmarkId: number, tagIds: number[]): void {
  db.prepare("DELETE FROM bookmark_tags WHERE bookmark_id = ?").run(bookmarkId);

  const insert = db.prepare("INSERT INTO bookmark_tags (bookmark_id, tag_id) VALUES (?, ?)");
  for (const tagId of tagIds) {
    insert.run(bookmarkId, tagId);
  }
}

function attachTagsToBookmarks(bookmarks: Bookmark[], userId: number): BookmarkWithTags[] {
  const tagsByBookmark = new Map<number, Tag[]>();
  for (const bookmark of bookmarks) {
    tagsByBookmark.set(bookmark.id, []);
  }

  if (bookmarks.length === 0) {
    return [];
  }

  const bookmarkIds = bookmarks.map((bookmark) => bookmark.id);
  const placeholders = bookmarkIds.map(() => "?").join(", ");
  const rows = db
    .prepare(
      `
        SELECT
          bookmark_tags.bookmark_id,
          tags.id,
          tags.user_id,
          tags.name,
          tags.created_at,
          tags.updated_at
        FROM bookmark_tags
        INNER JOIN tags ON tags.id = bookmark_tags.tag_id
        WHERE tags.user_id = ? AND bookmark_tags.bookmark_id IN (${placeholders})
        ORDER BY tags.id ASC
      `,
    )
    .all(userId, ...bookmarkIds) as Array<Tag & { bookmark_id: number }>;

  for (const row of rows) {
    const { bookmark_id, ...tag } = row;
    tagsByBookmark.get(bookmark_id)?.push(tag);
  }

  return bookmarks.map((bookmark) => ({
    ...bookmark,
    tags: tagsByBookmark.get(bookmark.id) ?? [],
  }));
}

function getExportPayload(userId: number): ImportPayload {
  const folders = db
    .prepare("SELECT id, name FROM folders WHERE user_id = ? ORDER BY id ASC")
    .all(userId) as ImportFolder[];
  const tags = db.prepare("SELECT id, name FROM tags WHERE user_id = ? ORDER BY id ASC").all(userId) as ImportTag[];
  const bookmarks = db
    .prepare(
      `
        SELECT id, url, title, description, folder_id
        FROM bookmarks
        WHERE user_id = ?
        ORDER BY id ASC
      `,
    )
    .all(userId) as ExportBookmarkRow[];
  const bookmarksWithTags = attachTagsToBookmarks(
    bookmarks.map((bookmark) => ({
      ...bookmark,
      user_id: userId,
      created_at: "",
      updated_at: "",
    })),
    userId,
  );

  return {
    bookmarks: bookmarksWithTags.map((bookmark) => ({
      id: bookmark.id,
      url: bookmark.url,
      title: bookmark.title,
      description: bookmark.description,
      folder_id: bookmark.folder_id,
      tag_ids: bookmark.tags.map((tag) => tag.id),
      tags: bookmark.tags.map((tag) => ({ id: tag.id, name: tag.name })),
    })),
    folders,
    tags,
  };
}

function arraysEqual(left: number[], right: number[]): boolean {
  if (left.length !== right.length) {
    return false;
  }

  const sortedLeft = [...left].sort((a, b) => a - b);
  const sortedRight = [...right].sort((a, b) => a - b);
  return sortedLeft.every((value, index) => value === sortedRight[index]);
}

function getBookmarkTagIds(bookmarkId: number): number[] {
  const rows = db
    .prepare("SELECT tag_id FROM bookmark_tags WHERE bookmark_id = ? ORDER BY tag_id ASC")
    .all(bookmarkId) as Array<{ tag_id: number }>;
  return rows.map((row) => row.tag_id);
}

function resolveImportTagIds(bookmark: ImportBookmark, tagIdBySourceId: Map<number, number>, tagIdByName: Map<string, number>): number[] {
  const tagIds = new Set<number>();

  for (const sourceTagId of bookmark.tag_ids ?? []) {
    const tagId = tagIdBySourceId.get(sourceTagId);
    if (tagId) {
      tagIds.add(tagId);
    }
  }

  for (const tag of bookmark.tags ?? []) {
    const tagId = tagIdByName.get(tag.name);
    if (tagId) {
      tagIds.add(tagId);
    }
  }

  return [...tagIds];
}

function importPayload(payload: ImportPayload, userId: number): ImportSummary {
  const summary: ImportSummary = { imported: 0, skipped: 0, updated: 0 };
  const folderIdBySourceId = new Map<number, number>();
  const tagIdBySourceId = new Map<number, number>();
  const tagIdByName = new Map<string, number>();
  const now = new Date().toISOString();

  const runImport = db.transaction(() => {
    for (const folder of payload.folders) {
      let targetFolder = getFolderByName(folder.name, userId);
      if (targetFolder) {
        summary.skipped += 1;
      } else {
        const result = db
          .prepare(
            `
              INSERT INTO folders (user_id, name, created_at, updated_at)
              VALUES (?, ?, ?, ?)
            `,
          )
          .run(userId, folder.name, now, now);
        targetFolder = getFolder(Number(result.lastInsertRowid), userId);
        summary.imported += 1;
      }

      if (folder.id && targetFolder) {
        folderIdBySourceId.set(folder.id, targetFolder.id);
      }
    }

    for (const tag of payload.tags) {
      let targetTag = getTagByName(tag.name, userId);
      if (targetTag) {
        summary.skipped += 1;
      } else {
        const result = db
          .prepare(
            `
              INSERT INTO tags (user_id, name, created_at, updated_at)
              VALUES (?, ?, ?, ?)
            `,
          )
          .run(userId, tag.name, now, now);
        targetTag = getTag(Number(result.lastInsertRowid), userId);
        summary.imported += 1;
      }

      if (targetTag) {
        tagIdByName.set(tag.name, targetTag.id);
        if (tag.id) {
          tagIdBySourceId.set(tag.id, targetTag.id);
        }
      }
    }

    for (const bookmark of payload.bookmarks) {
      const normalizedUrl = normalizeUrl(bookmark.url);
      if (!normalizedUrl) {
        throw new Error("invalid import URL after validation");
      }

      const targetFolderId =
        typeof bookmark.folder_id === "number" ? folderIdBySourceId.get(bookmark.folder_id) ?? null : null;
      const targetTagIds = resolveImportTagIds(bookmark, tagIdBySourceId, tagIdByName);
      const existing = getBookmarkByNormalizedUrl(normalizedUrl, userId);

      if (!existing) {
        const result = db
          .prepare(
            `
              INSERT INTO bookmarks (user_id, url, title, description, folder_id, created_at, updated_at)
              VALUES (?, ?, ?, ?, ?, ?, ?)
            `,
          )
          .run(userId, bookmark.url, bookmark.title, bookmark.description ?? null, targetFolderId, now, now);
        replaceBookmarkTags(Number(result.lastInsertRowid), targetTagIds);
        summary.imported += 1;
        continue;
      }

      const existingTagIds = getBookmarkTagIds(existing.id);
      const needsUpdate =
        existing.title !== bookmark.title ||
        existing.description !== (bookmark.description ?? null) ||
        existing.folder_id !== targetFolderId ||
        !arraysEqual(existingTagIds, targetTagIds);

      if (!needsUpdate) {
        summary.skipped += 1;
        continue;
      }

      db.prepare(
        `
          UPDATE bookmarks
          SET title = ?, description = ?, folder_id = ?, updated_at = ?
          WHERE id = ? AND user_id = ?
        `,
      ).run(bookmark.title, bookmark.description ?? null, targetFolderId, now, existing.id, userId);
      replaceBookmarkTags(existing.id, targetTagIds);
      summary.updated += 1;
    }
  });

  runImport();
  return summary;
}

function buildTagFilterSql(tagNames: string[]): { clause: string; params: string[] } {
  const clauses = tagNames.map(
    () => `
      AND EXISTS (
        SELECT 1
        FROM bookmark_tags
        INNER JOIN tags ON tags.id = bookmark_tags.tag_id
        WHERE bookmark_tags.bookmark_id = bookmarks.id
          AND tags.user_id = bookmarks.user_id
          AND tags.name = ?
      )
    `,
  );

  return {
    clause: clauses.join("\n"),
    params: tagNames,
  };
}

function buildSearchSql(search: SearchQuery | null): {
  clause: string;
  params: string[];
  orderBy: string;
  orderParams: string[];
} {
  if (!search) {
    return {
      clause: "",
      params: [],
      orderBy: "bookmarks.id ASC",
      orderParams: [],
    };
  }

  const matchClause = `
    AND (
      lower(bookmarks.title) LIKE ? ESCAPE '\\'
      OR lower(bookmarks.url) LIKE ? ESCAPE '\\'
      OR lower(COALESCE(bookmarks.description, '')) LIKE ? ESCAPE '\\'
      OR EXISTS (
        SELECT 1
        FROM folders
        WHERE folders.id = bookmarks.folder_id
          AND folders.user_id = bookmarks.user_id
          AND lower(folders.name) LIKE ? ESCAPE '\\'
      )
      OR EXISTS (
        SELECT 1
        FROM bookmark_tags
        INNER JOIN tags ON tags.id = bookmark_tags.tag_id
        WHERE bookmark_tags.bookmark_id = bookmarks.id
          AND tags.user_id = bookmarks.user_id
          AND lower(tags.name) LIKE ? ESCAPE '\\'
      )
    )
  `;

  return {
    clause: matchClause,
    params: [
      search.containsPattern,
      search.containsPattern,
      search.containsPattern,
      search.containsPattern,
      search.containsPattern,
    ],
    orderBy: `
      CASE
        WHEN lower(bookmarks.title) = ? THEN 0
        WHEN lower(bookmarks.title) LIKE ? ESCAPE '\\' THEN 1
        WHEN lower(bookmarks.title) LIKE ? ESCAPE '\\' THEN 2
        ELSE 3
      END ASC,
      bookmarks.id ASC
    `,
    orderParams: [search.normalized, search.prefixPattern, search.containsPattern],
  };
}

