      `
        SELECT id, user_id, url, title, description, folder_id, created_at, updated_at
        FROM bookmarks
        WHERE user_id = ?
        ORDER BY id ASC
      `,
    )
    .all(userId) as Bookmark[];

  return bookmarks.find((bookmark) => normalizeUrl(bookmark.url) === normalizedUrl);
}

function parseFolderId(value: unknown): number | null | undefined {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  if (typeof value === "number" && Number.isInteger(value) && value > 0) {
    return value;
  }

  return undefined;
}

function parseTagIds(value: unknown): number[] | undefined {
  if (value === undefined) {
    return [];
  }

  if (!Array.isArray(value)) {
    return undefined;
  }

  const uniqueIds = new Set<number>();
  for (const item of value) {
    const parsed = typeof item === "string" && /^\d+$/.test(item) ? Number(item) : item;
    if (typeof parsed !== "number" || !Number.isSafeInteger(parsed) || parsed <= 0) {
      return undefined;
    }

    uniqueIds.add(parsed);
  }

  return [...uniqueIds];
}

function isPlainObject(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

function parseOptionalPositiveInteger(value: unknown): number | undefined {
  if (value === undefined) {
    return undefined;
  }

  return typeof value === "number" && Number.isSafeInteger(value) && value > 0 ? value : undefined;
}

function parseImportTag(value: unknown): ImportTag | undefined {
  if (!isPlainObject(value)) {
    return undefined;
  }

  const { id, name } = value;
  const parsedId = parseOptionalPositiveInteger(id);
  if (id !== undefined && parsedId === undefined) {
    return undefined;
  }

  if (!isNonEmptyString(name)) {
    return undefined;
  }

  return {
    ...(parsedId ? { id: parsedId } : {}),
    name: name.trim(),
  };
}

function parseImportFolder(value: unknown): ImportFolder | undefined {
  if (!isPlainObject(value)) {
    return undefined;
  }

  const { id, name } = value;
  const parsedId = parseOptionalPositiveInteger(id);
  if (id !== undefined && parsedId === undefined) {
    return undefined;
  }

  if (!isNonEmptyString(name)) {
    return undefined;
  }

  return {
    ...(parsedId ? { id: parsedId } : {}),
    name: name.trim(),
  };
}

function parseImportBookmark(value: unknown): ImportBookmark | undefined {
  if (!isPlainObject(value)) {
    return undefined;
  }

  const { id, url, title, description, folder_id, tag_ids, tags } = value;
  const parsedId = parseOptionalPositiveInteger(id);
  if (id !== undefined && parsedId === undefined) {
    return undefined;
  }

  if (!isNonEmptyString(url) || !isValidUrl(url) || !isNonEmptyString(title)) {
    return undefined;
  }

  if (description !== undefined && description !== null && typeof description !== "string") {
    return undefined;
  }

  const parsedFolderId = parseFolderId(folder_id);
  if (folder_id !== undefined && parsedFolderId === undefined) {
    return undefined;
  }

  const parsedTagIds = parseTagIds(tag_ids);
  if (parsedTagIds === undefined) {
    return undefined;
  }

  let parsedTags: ImportTag[] | undefined;
  if (tags !== undefined) {
    if (!Array.isArray(tags)) {
      return undefined;
    }

    parsedTags = [];
    for (const tag of tags) {
      const parsedTag = parseImportTag(tag);
      if (!parsedTag) {
        return undefined;
      }
      parsedTags.push(parsedTag);
    }
  }

  return {
    ...(parsedId ? { id: parsedId } : {}),
    url: url.trim(),
    title: title.trim(),
    description: typeof description === "string" && description.length > 0 ? description : null,
    ...(folder_id !== undefined ? { folder_id: parsedFolderId ?? null } : {}),
    tag_ids: parsedTagIds,
    ...(parsedTags ? { tags: parsedTags } : {}),
  };
}

function parseImportPayload(value: unknown): ImportPayload | undefined {
  if (!isPlainObject(value) || !Array.isArray(value.bookmarks) || !Array.isArray(value.folders) || !Array.isArray(value.tags)) {
    return undefined;
  }

  const folders: ImportFolder[] = [];
  for (const folder of value.folders) {
    const parsedFolder = parseImportFolder(folder);
    if (!parsedFolder) {
      return undefined;
    }
    folders.push(parsedFolder);
  }

  const tags: ImportTag[] = [];
  for (const tag of value.tags) {
    const parsedTag = parseImportTag(tag);
    if (!parsedTag) {
      return undefined;
    }
    tags.push(parsedTag);
  }

  const bookmarks: ImportBookmark[] = [];
  for (const bookmark of value.bookmarks) {
    const parsedBookmark = parseImportBookmark(bookmark);
    if (!parsedBookmark) {
      return undefined;
    }
    bookmarks.push(parsedBookmark);
  }

  return { bookmarks, folders, tags };
}

function parseTagFilterQuery(query: Request["query"]): string[] | undefined {
  const tagValues: string[] = [];

  if (query.tag !== undefined) {
    if (typeof query.tag !== "string" || !isNonEmptyString(query.tag)) {
      return undefined;
    }
    tagValues.push(query.tag);
  }

  if (query.tags !== undefined) {
    if (typeof query.tags !== "string" || !isNonEmptyString(query.tags)) {
      return undefined;
    }
    tagValues.push(...query.tags.split(","));
  }

  const names = tagValues.map((name) => name.trim()).filter((name) => name.length > 0);
  if (tagValues.length > 0 && names.length !== tagValues.length) {
    return undefined;

  const authorization = req.header("Authorization");
  const [scheme, token] = authorization?.split(" ") ?? [];

  if (scheme !== "Bearer" || !token) {
    return res.status(401).json({ error: "authentication required" });
  }

  try {
    const payload = jwt.verify(token, JWT_SECRET);
    const userId = typeof payload === "object" && payload !== null ? payload.userId : undefined;

    if (typeof userId !== "number" || !Number.isInteger(userId) || !getUserById(userId)) {
      return res.status(401).json({ error: "invalid token" });
    }

    req.userId = userId;
    return next();
  } catch {
    return res.status(401).json({ error: "invalid token" });
  }
}

