+        summary.skipped += 1;
+      } else {
+        const result = db
+          .prepare(
+            `
+              INSERT INTO folders (user_id, name, created_at, updated_at)
+              VALUES (?, ?, ?, ?)
+            `,
+          )
+          .run(userId, folder.name, now, now);
+        targetFolder = getFolder(Number(result.lastInsertRowid), userId);
+        summary.imported += 1;
+      }
+
+      if (folder.id && targetFolder) {
+        folderIdBySourceId.set(folder.id, targetFolder.id);
+      }
+    }
+
+    for (const tag of payload.tags) {
+      let targetTag = getTagByName(tag.name, userId);
+      if (targetTag) {
+        summary.skipped += 1;
+      } else {
+        const result = db
+          .prepare(
+            `
+              INSERT INTO tags (user_id, name, created_at, updated_at)
+              VALUES (?, ?, ?, ?)
+            `,
+          )
+          .run(userId, tag.name, now, now);
+        targetTag = getTag(Number(result.lastInsertRowid), userId);
+        summary.imported += 1;
+      }
+
+      if (targetTag) {
+        tagIdByName.set(tag.name, targetTag.id);
+        if (tag.id) {
+          tagIdBySourceId.set(tag.id, targetTag.id);
+        }
+      }
