+        typeof bookmark.folder_id === "number" ? folderIdBySourceId.get(bookmark.folder_id) ?? null : null;
+      const targetTagIds = resolveImportTagIds(bookmark, tagIdBySourceId, tagIdByName);
+      const existing = getBookmarkByNormalizedUrl(normalizedUrl, userId);
